import random

def article():
    articles = [
        "Лето, которого мы боялись: глобальное потепление и экстремальные температуры в 2026 году. В 2026 году Земля может войти в топ-4 самых тёплых лет с 1850 года. Средняя температура превысит доиндустриальный уровень более чем на 1,4°C. Это приведёт к частым волнам жары, засухам, лесным пожарам и наводнениям. Особенно быстро нагревается Арктика, где тает морской лёд и ледяной щит Гренландии, что угрожает повышением уровня моря. Прогнозируется средний по числу, но потенциально опасный сезон ураганов. Учёные отмечают, что даже кратковременные скачки температуры вызывают цепные реакции в экосистемах и экономике.",
        "Страшный прогноз метеорологов на конец 2026: скрытый резервуар тепла в океане изменит погоду до неузнаваемости. Под тропической частью Тихого океана обнаружен гигантский резервуар тепла. Его перемещение предвещает резкую смену климатических фаз и усиление погодных аномалий к концу 2026 года. Этот скрытый механизм может привести к неожиданным и масштабным изменениям погоды по всему миру",
        "Глобальное потепление в России и мире 2026: причины изменения климата и пути решения. За последние 100 лет средняя температура на планете выросла на 1°C. Основные причины — сжигание ископаемого топлива, выбросы парниковых газов, вырубка лесов, промышленное производство и транспорт. Последствия: подъём уровня моря, таяние ледников, экстремальные погодные явления, нарушение экосистем и риски для здоровья. В статье рассматриваются меры по борьбе с изменением климата — от перехода на зелёную энергетику до экопривычек в быту.",
        "Глобальное потепление может привести к вечному снегу в России. Какие города придётся переселять. Климатолог Алексей Карнаухов предупреждает: глобальное потепление может парадоксально привести к похолоданию в европейской части России. Из-за нарушения циркуляции атмосферы и таяния арктических льдов снег может перестать таять даже летом. Под угрозой переселения окажутся Санкт-Петербург, Мурманск, Архангельск и даже Москва. Возможен сценарий нового ледникового периода для части страны."
    ]
    return random.choice(articles)

def fact():
    facts = [
        "Температура растёт быстрее, чем ожидалось. За последние 100 лет средняя температура на Земле уже повысилась примерно на 1°C, и темпы потепления продолжают ускоряться. Прогнозы показывают, что к 2030 году мир может достичь роста на 1,5°C по сравнению с доиндустриальным уровнем, что считается критическим порогом для устойчивости климатической системы.",
        "Основные причины — деятельность человека. Главные источники глобального потепления — сжигание ископаемого топлива (уголь, нефть, газ), промышленные выбросы, массовая вырубка лесов и сельское хозяйство. Всё это приводит к увеличению концентрации парниковых газов (углекислый газ, метан, оксид азота) в атмосфере, которые удерживают тепло и усиливают парниковый эффект.",
        "Последствия ощущаются по всему миру. Глобальное потепление вызывает таяние ледников и арктических льдов, подъём уровня Мирового океана, учащение и усиление экстремальных погодных явлений (ураганы, засухи, наводнения), а также нарушение экосистем и исчезновение видов. В России, например, возможны как аномальная жара, так и парадоксальное похолодание в отдельных регионах.",
        "Меры по борьбе требуют глобальных усилий. Для замедления потепления необходим переход на возобновляемые источники энергии, сокращение выбросов, восстановление лесов, развитие «зелёных» технологий и изменение потребительских привычек. Международные соглашения, такие как Парижское соглашение, направлены на удержание роста температуры ниже 2°C, но для этого нужны совместные действия государств, бизнеса и каждого человека."
    ]
    return random.choice(facts) # Исправлено: facts вместо fact